const base = this.frm_gen_fecha_solicitud || new Date().toISOString().slice(0,10);
const d = new Date(`${base}T00:00:00`);
d.setDate(d.getDate() + 180);
return d.toISOString().slice(0,10);

const base = this.frm_gen_fecha_solicitud || new Date().toISOString().slice(0,10);
const d = new Date(`${base}T00:00:00`); // evita desfaces de zona
d.setDate(d.getDate() - 120);
return d.toISOString().slice(0,10);

const frm_gen_tipo_coaseguro = this.frm_gen_tipo_coaseguro;
const frm_gen_tipo_reaseguro = this.frm_gen_tipo_reaseguro;
const frm_gen_coaseguro_requerido = this.frm_gen_coaseguro_requerido;
const frm_gen_reaseguro_requerido = this.frm_gen_reaseguro_requerido;

/*if (frm_gen_tipo_reaseguro == "CEDIDO"){
    return "Seguidor"
}
if (frm_gen_tipo_coaseguro == "CEDIDO"){
    return "Líder"*/
if (frm_gen_tipo_coaseguro == "ACEPTADO" || frm_gen_tipo_reaseguro == "ACEPTADO"){
    return "Seguidor"
} else {
    return "Líder"
}

const toDate = (s) => s ? new Date(`${s}T00:00:00`) : null;
const fmt = (d) => d ? [
  String(d.getDate()).padStart(2,'0'),
  String(d.getMonth()+1).padStart(2,'0'),
  d.getFullYear()
].join('/') : '—';

const vStr   = this.frm_gen_fecha_esperada_cotizacion;
const minStr = this.frm_gen_fecha_esperada_cotizacion_minimo;
const maxStr = this.frm_gen_fecha_esperada_cotizacion_maximo;

const v   = toDate(vStr);
const min = toDate(minStr);
const max = toDate(maxStr);

setTimeout(() => {
  const input = document.querySelector('input[name="frm_gen_fecha_esperada_cotizacion"]');
  if (input) {
    if (minStr) input.setAttribute('min', minStr);
    if (maxStr) input.setAttribute('max', maxStr);
  }
}, 0);

if (!v || !min || !max) {
  return this.frm_gen_fecha_esperada_cotizacion ?? null;
}

const outOfRange = (v < min) || (v > max);

setTimeout(() => {
  const input = document.querySelector('input[name="frm_gen_fecha_esperada_cotizacion"]');
  const group = input?.closest('.form-group');

  if (group) {
    const prev = group.querySelector('.invalid-feedback');
    if (prev) prev.remove();
  }
  input?.classList.remove('is-invalid');

  if (outOfRange) {
    if (input && !input.classList.contains('is-invalid')) input.classList.add('is-invalid');
    if (group && !group.querySelector('.invalid-feedback')) {
      const msg = document.createElement('div');
      msg.className = 'invalid-feedback d-block';
      msg.innerHTML = `<div>La fecha debe estar entre ${fmt(min)} y ${fmt(max)}.</div>`;
      group.insertBefore(msg, group.querySelector('small.form-text'));
    }

    /*
    const MODAL_ID = 'modal_fecha_invalida';
    const BTN_SEL  = '[custom-css-selector="btn_preventivo"]';
    const now = Date.now();
    window.__iv_lastModalAt = window.__iv_lastModalAt || 0;
    if ((now - window.__iv_lastModalAt) > 600) {
      const boton = document.querySelector(BTN_SEL);
      if (boton?.__vue__?.$root?.$bvModal) boton.__vue__.$root.$bvModal.show(MODAL_ID);
      window.__iv_lastModalAt = now;
    }
    */
  }
}, 250);

if (outOfRange) return null;
return this.frm_gen_fecha_esperada_cotizacion;

const frm_riesgo_validezDias = this.frm_riesgo_validezDias;

if (frm_riesgo_validezDias === null || frm_riesgo_validezDias === undefined || frm_riesgo_validezDias === "") {
  return "";
}

return `${frm_riesgo_validezDias} días`;

